GRANT SELECT ON public.ab_variants TO anon, authenticated; GRANT INSERT, UPDATE, DELETE ON public.ab_variants TO authenticated; GRANT ALL ON public.ab_variants TO service_role; INSERT INTO public.ab_variants (variant, label, headline, sub_headline) VALUES ('A','Ciclo genérico','NÃO É AZAR. É UM CICLO. E TODO CICLO PODE SER QUEBRADO.','Faça o teste de 2 minutos, descubra quais dos **7 CICLOS** estão te prendendo e receba o plano exato pra quebrar cada ciclo.'), ('B','Família / filhos','O CICLO DA SUA FAMÍLIA NÃO PAROU EM VOCÊ. ELE JÁ ESTÁ INDO PROS SEUS FILHOS.','Descubra em 2 minutos qual ciclo você está repetindo — e como ser a pessoa que **quebra o ciclo** antes que ele passe adiante.'), ('C','Ciclo invisível','EXISTE UM CICLO INVISÍVEL DECIDINDO SUA VIDA POR VOCÊ. DESCUBRA QUAL É.','2 minutos pra mapear os **7 CICLOS** que te travam e receber um plano personalizado pra romper ciclo por ciclo.'), ('D','Quebrador de ciclo','TODA FAMÍLIA TEM UM CICLO. E TODA FAMÍLIA PRECISA DE ALGUÉM PRA QUEBRÁ-LO.','Faça o teste e descubra se você já é quem vai **quebrar o ciclo** da sua família — ou o que ainda te separa disso.'), ('E','Coragem / sobrenome','A PERGUNTA NÃO É QUEM CRIOU O CICLO. É QUEM VAI TER CORAGEM DE QUEBRAR O CICLO.','Se for você, este teste mostra onde o ciclo começa — e como **quebrar um único ciclo** muda o sobrenome inteiro.') ON CONFLICT (variant) DO NOTHING;